qry:select.qry:xquery:
for $r in sql(' SELECT PER02_PERSONAL_EMP.oi_personal_emp, PER01_PERSONAL.d_ape_y_nom, PER02_PERSONAL_EMP.e_numero_legajo, ORG18_CATEGORIAS.d_categoria, ORG18_CONVENIOS.d_convenio, PER02_LICEN_PER.oi_licencia_per, PER02_LICEN_PER.f_notificacion, PER02_LICEN_PER.f_inicio, PER02_LICEN_PER.o_licencia_per, IIFISNULL(PER02_LICEN_PER.f_interrupcion,PER02_LICEN_PER.f_fin) AS f_fin, PER02_LICEN_PER.f_fin AS f_fin_orig, PER16_LICENCIAS.d_licencia FROM PER02_PERSONAL_EMP , PER01_PERSONAL , PER02_LICEN_PER , PER16_LICENCIAS , ORG18_CATEGORIAS , ORG18_CONVENIOS JOIN PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal , PER02_LICEN_PER.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp , PER16_LICENCIAS.oi_licencia INNER PER02_LICEN_PER.oi_licencia , ORG18_CATEGORIAS.oi_categoria INNER PER02_PERSONAL_EMP.oi_categoria_ult , ORG18_CONVENIOS.oi_convenio INNER ORG18_CATEGORIAS.oi_convenio WHERE PER02_PERSONAL_EMP.oi_empresa = {#PARAMIN:@oi_empresa} {%? (string(#PARAMIN:@boolEnPeriodo)!='1') {% AND ((PER02_LICEN_PER.f_inicio >= {Datetime(#PARAMIN:@f_desde)} AND PER02_LICEN_PER.f_inicio <= {Datetime(#PARAMIN:@f_hasta)}) OR (PER02_LICEN_PER.f_fin >= {Datetime(#PARAMIN:@f_desde)} AND PER02_LICEN_PER.f_fin <= {Datetime(#PARAMIN:@f_hasta)}) OR (PER02_LICEN_PER.f_inicio <= {Datetime(#PARAMIN:@f_desde)} AND PER02_LICEN_PER.f_fin >= {Datetime(#PARAMIN:@f_hasta)})) %} {% AND PER02_LICEN_PER.f_inicio >= {Datetime(#PARAMIN:@f_desde)} AND PER02_LICEN_PER.f_fin <= {Datetime(#PARAMIN:@f_hasta)} %} %}
{%? (string(#PARAMIN:ROWS/ROW/@id)!='') {% AND PER02_LICEN_PER.oi_licencia in ({%=string(#PARAMIN:ROWS/ROW/@id) %}) %} {% %} %} {%? (string(#PARAMIN:@notif)='1') {% AND isNotNull(PER02_LICEN_PER.f_notificacion) %} {% {%? (string(#PARAMIN:@notif)='2') {% AND isNull(PER02_LICEN_PER.f_notificacion) %} {% %} %} %} %}
ORDER BY f_inicio DESC ')/ROWS/ROW
